module.render:
const size = args.size || '1em';
const color = args.color || 'currentColor';
const direction = (args.direction || 'right').toLowerCase();
const shape = (args.shape || 'line').toLowerCase();
const wm = { thin: 0.7, normal: 1, bold: 1.4 }[String(args.weight || 'normal').toLowerCase()] || 1;
const sw = (n) => +(n * wm).toFixed(1);
const sp = { tight: '0.05em', normal: '0.15em', wide: '0.3em' }[String(args.spacing || 'normal').toLowerCase()] || '0.15em';
// Shapes are drawn pointing RIGHT (0deg); direction rotates the glyph.
const angles = {
  right: 0, 'down-right': 45, down: 90, 'down-left': 135,
  left: 180, 'up-left': 225, up: 270, 'up-right': 315
};
const angle = angles[direction] != null ? angles[direction] : 0;
const shapes = {
  triangle: '<polygon points="26,16 84,50 26,84"/>',
  chevron: `<polyline points="36,18 70,50 36,82" fill="none" stroke="currentColor" stroke-width="${sw(14)}" stroke-linecap="round" stroke-linejoin="round"/>`,
  line: `<path d="M8 50 H72" fill="none" stroke="currentColor" stroke-width="${sw(10)}" stroke-linecap="round"/><polyline points="58,28 86,50 58,72" fill="none" stroke="currentColor" stroke-width="${sw(10)}" stroke-linecap="round" stroke-linejoin="round"/>`,
  double: `<polyline points="22,20 52,50 22,80" fill="none" stroke="currentColor" stroke-width="${sw(12)}" stroke-linecap="round" stroke-linejoin="round"/><polyline points="48,20 78,50 48,80" fill="none" stroke="currentColor" stroke-width="${sw(12)}" stroke-linecap="round" stroke-linejoin="round"/>`
};
const inner = shapes[shape] || shapes.line;
return `<span class="mdp-mod-iarrow" style="color:${color}; margin:0 ${sp};"><svg viewBox="0 0 100 100" style="width:${size};height:${size};transform:rotate(${angle}deg);" fill="currentColor" aria-hidden="true">${inner}</svg></span>`;
